#include <stdio.h>
#include <string.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume the newline after T
    char line[101];
    while (T--) {
        if (fgets(line, sizeof(line), stdin) == NULL) {
            line[0] = '\0';
        }
        line[strcspn(line, "\n")] = '\0'; // remove trailing newline
        printf("%s\n", line);
    }
    return 0;
}

